import { tooltipDatapoint } from './styles.sty.js';
import { BubbleShape } from '../../../shape/BubbleShape/BubbleShape.js';
import { MultiDataPointShape } from '../../../shape/MultiDataPointShape.js';
import { SingleDataPointShape } from '../../../shape/SingleDataPointShape.js';
import { SymbolAtom } from '../../../tooltip-atoms/components/SymbolAtom.js';
import type { TooltipIndicatorProps } from '../../types/tooltip.js';

export const TooltipPointIndicator = (props: TooltipIndicatorProps) => {
  const { color, variant = 'single', active = false, ...rest } = props;

  switch (variant) {
    case 'single': {
      return (
        <div className={tooltipDatapoint} {...rest}>
          <SymbolAtom>
            <SingleDataPointShape color={color} active={active} />
          </SymbolAtom>
        </div>
      );
    }
    case 'multi': {
      return (
        <div className={tooltipDatapoint} {...rest}>
          <SymbolAtom>
            <MultiDataPointShape color={color} active={active} />
          </SymbolAtom>
        </div>
      );
    }
    case 'bubble': {
      return (
        <div className={tooltipDatapoint} {...rest}>
          <SymbolAtom>
            <BubbleShape color={color} active={active} />
          </SymbolAtom>
        </div>
      );
    }
  }
};

TooltipPointIndicator['displayName'] = 'TooltipPointIndicator';
